/*
** GLR (Generalized LR) parser support for Lime.
**
** This module implements a Graph-Structured Stack (GSS) and the GLR
** parsing algorithm on top of the LALR(1) tables generated by Lime.
** When a shift/reduce or reduce/reduce conflict is encountered at
** runtime, the parser forks into multiple parallel stack heads rather
** than reporting an error. Heads that converge to the same state are
** merged, optionally using a user-provided disambiguation callback.
*/

#include "glr.h"
#include "lime_ast.h"

#include <stdlib.h>
#include <string.h>

#define GLR_INITIAL_HEADS 16
#define GLR_INITIAL_PREDS 4
#define GLR_DEFAULT_ARENA (64 * 1024)

/* ------------------------------------------------------------------ */
/* GSSNode operations                                                  */
/* ------------------------------------------------------------------ */

GSSNode *gss_node_create(LimeArena *arena, uint32_t state) {
    GSSNode *node = (GSSNode *)lime_arena_calloc(arena, sizeof(GSSNode));
    if (!node) return NULL;
    node->state = state;
    node->refcount = 1;
    node->npred = 0;
    node->pred_capacity = 0;
    node->predecessors = NULL;
    return node;
}

void gss_node_add_predecessor(GSSNode *node, GSSNode *pred) {
    if (!node || !pred) return;

    /* Grow predecessors array if needed */
    if (node->npred >= node->pred_capacity) {
        uint32_t new_cap = node->pred_capacity == 0 ? GLR_INITIAL_PREDS : node->pred_capacity * 2;
        GSSNode **new_preds = (GSSNode **)realloc(node->predecessors, new_cap * sizeof(GSSNode *));
        if (!new_preds) return; /* allocation failure - silently drop */
        node->predecessors = new_preds;
        node->pred_capacity = new_cap;
    }

    node->predecessors[node->npred++] = pred;
    gss_node_acquire(pred);
}

GSSNode *gss_node_acquire(GSSNode *node) {
    if (node) node->refcount++;
    return node;
}

void gss_node_release(GSSNode *node) {
    if (!node) return;
    if (node->refcount > 0) node->refcount--;
    /* Note: actual deallocation is handled by the arena.
    ** The refcount is used to track logical liveness for
    ** predecessor cleanup. We free the predecessors array
    ** (which is heap-allocated) when refcount reaches zero. */
    if (node->refcount == 0 && node->predecessors) {
        /* Release all predecessors recursively */
        for (uint32_t i = 0; i < node->npred; i++) {
            gss_node_release(node->predecessors[i]);
        }
        free(node->predecessors);
        node->predecessors = NULL;
        node->npred = 0;
        node->pred_capacity = 0;
    }
}

/* ------------------------------------------------------------------ */
/* GLRParser lifecycle                                                  */
/* ------------------------------------------------------------------ */

GLRParser *glr_parser_create(uint32_t initial_state, size_t arena_size) {
    GLRParser *parser = (GLRParser *)calloc(1, sizeof(GLRParser));
    if (!parser) return NULL;

    if (arena_size == 0) arena_size = GLR_DEFAULT_ARENA;
    parser->arena = lime_arena_create(arena_size);
    if (!parser->arena) {
        free(parser);
        return NULL;
    }

    parser->max_heads = GLR_INITIAL_HEADS;
    parser->active_heads = (GSSNode **)calloc(parser->max_heads, sizeof(GSSNode *));
    if (!parser->active_heads) {
        lime_arena_destroy(parser->arena);
        free(parser);
        return NULL;
    }

    /* Create the initial GSS node at the start state */
    GSSNode *start = gss_node_create(parser->arena, initial_state);
    if (!start) {
        free(parser->active_heads);
        lime_arena_destroy(parser->arena);
        free(parser);
        return NULL;
    }
    parser->active_heads[0] = start;
    parser->nheads = 1;
    parser->total_forks = 0;
    parser->total_merges = 0;
    parser->has_ambiguity = false;

    return parser;
}

void glr_parser_destroy(GLRParser *parser) {
    if (!parser) return;

    /* Release all active head references */
    for (uint32_t i = 0; i < parser->nheads; i++) {
        gss_node_release(parser->active_heads[i]);
    }
    free(parser->active_heads);

    /* Arena destroys all GSSNode storage in bulk */
    lime_arena_destroy(parser->arena);
    free(parser);
}

/* ------------------------------------------------------------------ */
/* Internal helpers                                                     */
/* ------------------------------------------------------------------ */

/*
** Look up the shift action for a terminal token in a given state.
** Mirrors the yy_find_shift_action logic in limpar.c.
*/
static uint16_t find_shift_action(uint32_t stateno, uint16_t token, const uint16_t *yy_action,
                                  const uint16_t *yy_lookahead, const int16_t *yy_shift_ofst,
                                  const uint16_t *yy_default, uint32_t lookahead_count,
                                  uint32_t nstate) {
    if (stateno >= nstate) return yy_default[stateno];
    int32_t ofst = (int32_t)yy_shift_ofst[stateno];
    int32_t idx = ofst + (int32_t)token;
    if (idx >= 0 && (uint32_t)idx < lookahead_count && yy_lookahead[idx] == token) {
        return yy_action[idx];
    }
    return yy_default[stateno];
}

/*
** Look up the reduce (goto) action for a nonterminal after reduction.
** Mirrors yy_find_reduce_action in limpar.c.
*/
static uint16_t find_reduce_action(uint32_t stateno, uint16_t nonterminal,
                                   const uint16_t *yy_action, const uint16_t *yy_lookahead,
                                   const int16_t *yy_reduce_ofst, const uint16_t *yy_default,
                                   uint32_t lookahead_count) {
    int32_t ofst = (int32_t)yy_reduce_ofst[stateno];
    int32_t idx = ofst + (int32_t)nonterminal;
    if (idx >= 0 && (uint32_t)idx < lookahead_count && yy_lookahead[idx] == nonterminal) {
        return yy_action[idx];
    }
    return yy_default[stateno];
}

/*
** Grow the active_heads array if it is full.
*/
static int glr_grow_heads(GLRParser *parser) {
    uint32_t new_cap = parser->max_heads * 2;
    GSSNode **new_arr = (GSSNode **)realloc(parser->active_heads, new_cap * sizeof(GSSNode *));
    if (!new_arr) return -1;
    parser->active_heads = new_arr;
    parser->max_heads = new_cap;
    return 0;
}

/*
** Add a new head to the active set. Returns 0 on success, -1 on failure.
*/
static int glr_add_head(GLRParser *parser, GSSNode *node) {
    if (parser->nheads >= parser->max_heads) {
        if (glr_grow_heads(parser) != 0) return -1;
    }
    parser->active_heads[parser->nheads++] = gss_node_acquire(node);
    return 0;
}

/*
** Merge phase: after all heads have been processed for a token,
** merge any heads that have arrived at the same parser state.
** When two heads share a state, their predecessor lists are combined
** into a single node.
*/
static int glr_merge_heads(GLRParser *parser) {
    for (uint32_t i = 0; i < parser->nheads; i++) {
        if (!parser->active_heads[i]) continue;
        for (uint32_t j = i + 1; j < parser->nheads; j++) {
            if (!parser->active_heads[j]) continue;
            if (parser->active_heads[i]->state == parser->active_heads[j]->state) {
                /* Merge j into i: add j's predecessors to i */
                GSSNode *survivor = parser->active_heads[i];
                GSSNode *merged = parser->active_heads[j];

                for (uint32_t k = 0; k < merged->npred; k++) {
                    gss_node_add_predecessor(survivor, merged->predecessors[k]);
                }

                /* If no disambiguation callback, mark ambiguity */
                if (!parser->disambiguate) {
                    parser->has_ambiguity = true;
                }

                gss_node_release(merged);
                parser->active_heads[j] = NULL;
                parser->total_merges++;
            }
        }
    }

    /* Compact the heads array (remove NULLs) */
    uint32_t write = 0;
    for (uint32_t read = 0; read < parser->nheads; read++) {
        if (parser->active_heads[read]) {
            parser->active_heads[write++] = parser->active_heads[read];
        }
    }
    parser->nheads = write;

    return 0;
}

/* ------------------------------------------------------------------ */
/* Main feed function                                                  */
/* ------------------------------------------------------------------ */

int glr_parser_feed(GLRParser *parser, uint16_t token, const uint16_t *yy_action,
                    uint32_t action_count, const uint16_t *yy_lookahead, uint32_t lookahead_count,
                    const int16_t *yy_shift_ofst, const int16_t *yy_reduce_ofst,
                    const uint16_t *yy_default, uint32_t nstate, const uint16_t *yy_rule_lhs,
                    const int8_t *yy_rule_nrhs, uint32_t nrule, uint16_t min_shiftreduce,
                    uint16_t max_shiftreduce, uint16_t min_reduce, uint16_t max_reduce,
                    uint16_t error_action, uint16_t accept_action, uint16_t no_action) {
    (void)action_count;
    (void)max_reduce;
    (void)no_action;

    if (!parser || parser->nheads == 0) return -2;

    /*
    ** We process all current heads and build a new set of heads.
    ** This avoids issues with modifying the set while iterating.
    */
    uint32_t orig_nheads = parser->nheads;
    GSSNode **orig_heads = (GSSNode **)malloc(orig_nheads * sizeof(GSSNode *));
    if (!orig_heads) return -2;
    memcpy(orig_heads, parser->active_heads, orig_nheads * sizeof(GSSNode *));

    /* Clear active heads - we will rebuild */
    parser->nheads = 0;

    for (uint32_t h = 0; h < orig_nheads; h++) {
        GSSNode *head = orig_heads[h];
        uint32_t stateno = head->state;

        /* Find the primary action for this token in this state */
        uint16_t action = find_shift_action(stateno, token, yy_action, yy_lookahead, yy_shift_ofst,
                                            yy_default, lookahead_count, nstate);

        if (action == error_action) {
            /* This head dies - syntax error on this path */
            gss_node_release(head);
            continue;
        }

        if (action == accept_action) {
            /* Accept - keep this head as-is (accepted state) */
            GSSNode *accept_node = gss_node_create(parser->arena, accept_action);
            if (accept_node) {
                gss_node_add_predecessor(accept_node, head);
                glr_add_head(parser, accept_node);
                gss_node_release(accept_node);
            }
            gss_node_release(head);
            continue;
        }

        /*
        ** Determine if this is a shift, reduce, or shift-reduce.
        ** Also check if there's a secondary action (conflict) by
        ** checking if the default action provides an alternative.
        */
        bool did_shift = false;
        bool did_reduce = false;

        /* Handle shift or shift-reduce */
        if (action <= nstate || (action >= min_shiftreduce && action <= max_shiftreduce)) {
            uint32_t new_state;
            uint32_t reduce_rule = UINT32_MAX;

            if (action >= min_shiftreduce && action <= max_shiftreduce) {
                /* SHIFTREDUCE: shift then immediately reduce */
                reduce_rule = action - min_shiftreduce;
                /* The shift goes to an intermediate state; for GLR we
                ** model this as shift to a state that then reduces. */
                new_state = action; /* Encoded shift-reduce state */
            } else {
                new_state = action;
            }

            /* Create a new GSS node for the shifted state */
            GSSNode *shifted = gss_node_create(parser->arena, new_state);
            if (shifted) {
                gss_node_add_predecessor(shifted, head);

                if (reduce_rule != UINT32_MAX && reduce_rule < nrule) {
                    /* Perform the reduce after the shift.
                    ** Walk back |rhs| predecessors to find the base state,
                    ** then look up the goto action. */
                    int rhs_len = -(int)yy_rule_nrhs[reduce_rule];
                    uint16_t lhs = yy_rule_lhs[reduce_rule];

                    /* For a shift-reduce, we walk back through predecessors.
                    ** In the simple case (linear stack), we walk back rhs_len
                    ** steps from the shifted node. */
                    GSSNode *base = shifted;
                    for (int step = 0; step < rhs_len && base && base->npred > 0; step++) {
                        base = base->predecessors[0];
                    }
                    if (base) {
                        uint16_t goto_action =
                            find_reduce_action(base->state, lhs, yy_action, yy_lookahead,
                                               yy_reduce_ofst, yy_default, lookahead_count);
                        GSSNode *reduced = gss_node_create(parser->arena, goto_action);
                        if (reduced) {
                            gss_node_add_predecessor(reduced, base);
                            glr_add_head(parser, reduced);
                            gss_node_release(reduced);
                        }
                    } else {
                        /* Fallback: just keep the shifted node */
                        glr_add_head(parser, shifted);
                    }
                } else {
                    glr_add_head(parser, shifted);
                }
                gss_node_release(shifted);
            }
            did_shift = true;
        }

        /* Handle pure reduce */
        if (action >= min_reduce) {
            uint32_t rule_no = action - min_reduce;
            if (rule_no < nrule) {
                int rhs_len = -(int)yy_rule_nrhs[rule_no];
                uint16_t lhs = yy_rule_lhs[rule_no];

                /* Walk back rhs_len predecessors from this head */
                GSSNode *base = head;
                for (int step = 0; step < rhs_len && base && base->npred > 0; step++) {
                    base = base->predecessors[0];
                }
                if (base) {
                    uint16_t goto_action =
                        find_reduce_action(base->state, lhs, yy_action, yy_lookahead,
                                           yy_reduce_ofst, yy_default, lookahead_count);
                    GSSNode *reduced = gss_node_create(parser->arena, goto_action);
                    if (reduced) {
                        gss_node_add_predecessor(reduced, base);
                        /* After a reduce, we need to re-present the current token
                        ** to the new head. We add it back and it will be processed
                        ** on a subsequent call or in a reduce loop. For now, add
                        ** to the new heads. The caller should re-feed the token
                        ** if the head set changed. */
                        glr_add_head(parser, reduced);
                        gss_node_release(reduced);
                    }
                }
            }
            did_reduce = true;
        }

        /*
        ** Fork detection: Check if the default action provides an
        ** alternative to the primary action (S/R conflict).
        ** If the primary action was a shift, check if default is a reduce.
        ** If the primary action was a reduce, check if a shift was also valid.
        */
        if (did_shift && !did_reduce) {
            /* Check if the default action is a reduce we should also try */
            uint16_t def_action = yy_default[stateno];
            if (def_action >= min_reduce && def_action != action) {
                uint32_t rule_no = def_action - min_reduce;
                if (rule_no < nrule) {
                    int rhs_len = -(int)yy_rule_nrhs[rule_no];
                    uint16_t lhs = yy_rule_lhs[rule_no];

                    GSSNode *base = head;
                    for (int step = 0; step < rhs_len && base && base->npred > 0; step++) {
                        base = base->predecessors[0];
                    }
                    if (base) {
                        uint16_t goto_action =
                            find_reduce_action(base->state, lhs, yy_action, yy_lookahead,
                                               yy_reduce_ofst, yy_default, lookahead_count);
                        GSSNode *reduced = gss_node_create(parser->arena, goto_action);
                        if (reduced) {
                            gss_node_add_predecessor(reduced, base);
                            glr_add_head(parser, reduced);
                            gss_node_release(reduced);
                            parser->total_forks++;
                        }
                    }
                }
            }
        }

        gss_node_release(head);
    }

    free(orig_heads);

    /* If all heads died, parsing failed */
    if (parser->nheads == 0) return -2;

    /* Merge heads that arrived at the same state */
    glr_merge_heads(parser);

    /* Return status */
    if (parser->has_ambiguity && !parser->disambiguate) return -1;
    return 0;
}

/* ------------------------------------------------------------------ */
/* Configuration and query                                             */
/* ------------------------------------------------------------------ */

void glr_parser_set_disambiguate(GLRParser *parser, GLRDisambiguateFn fn, void *user_data) {
    if (!parser) return;
    parser->disambiguate = fn;
    parser->disambiguate_data = user_data;
}

uint32_t glr_parser_head_count(const GLRParser *parser) {
    if (!parser) return 0;
    return parser->nheads;
}

bool glr_parser_accepted(const GLRParser *parser, uint16_t accept_action) {
    if (!parser) return false;
    /* Accept is indicated by exactly one head in the accept state */
    if (parser->nheads != 1) return false;
    return parser->active_heads[0]->state == accept_action;
}
